  var f_gamma=function (n){
    if (!isFinite(n)) return n;
    if (n<-50){
      if (n==Math.trunc(n)) return Number.NEGATIVE_INFINITY;
      return 0;
    }
    var scal1=1;
    while (n<10){
      scal1=scal1*n;
      ++n;
    }
    n-=1;
    var l=0.9189385332046727; //0.5*Math.log(2*Math.PI)
    l+=(n+0.5)*Math.log(n);
    l-=n;
    var n2=n*n;
    var np=n;
    l+=1/(12*np);
    np*=n2;
    l-=1/(360*np);
    np*=np*n2;
    l+=1/(1260*np);
    np*=n2;
    l-=1/(1680*np);
    np*=n2;
    l+=1/(1188*np);
    np*=n2;
    l-=691/(360360*np);
    np*=n2;
    l+=7/(1092*np);
    np*=n2;
    l-=3617/(122400*np);
    return Math.exp(l)/scal1;
  };
